import React, { useEffect } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import HomePage from "./pages/HomePage";
import LoginPage from "./pages/LoginPage";
import SignupPage from "./pages/SignupPage";
import SettingPage from "./pages/SettingPage";
import PrivacyPage from "./pages/PrivacyPage";
import ProfilePage from "./pages/ProfilePage";
import ProPage from "./pages/ProPage";
import DeveloperPage from "./pages/DeveloperPage";
import { useAuthStore } from "./store/useAuthStore";
import { Loader } from "lucide-react";
import { Toaster } from "react-hot-toast";
import { useThemeStore } from "./store/useThemeStore";
import { useChatStore } from "./store/useChattingStore";
import { useVideoCallStore } from "./store/useVideoCallStore";
import { useVoiceCallStore } from "./store/useVoiceCallStore";
import VideoCall from "./components/VideoCall";
import VoiceCall from "./components/VoiceCall";

const App = () => {
  const { authUser, checkAuth, isCheckingAuth } = useAuthStore();
  const { theme } = useThemeStore();
  const { callStatus } = useVideoCallStore();
  const { callStatus: voiceCallStatus } = useVoiceCallStore();

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  useEffect(() => {
    if (authUser) {
      useVideoCallStore.getState().initializeListeners();
      useVoiceCallStore.getState().initializeListeners();
      useChatStore.getState().subscribeToPush();
      useChatStore.getState().subscribeToMessages();
    }
    return () => {
      useVideoCallStore.getState().cleanupListeners();
      useVoiceCallStore.getState().cleanupListeners();
      useChatStore.getState().unsubscribeFromMessages();
    };
  }, [authUser]);

  if (isCheckingAuth && !authUser)
    return (
      <div className="flex items-center justify-center h-screen">
        <Loader className="size-14 animate-spin" />
      </div>
    );
  return (
    <div data-theme={theme} className="chat-page w-full h-[100dvh] flex flex-col bg-base-100 overflow-hidden">
      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <Routes>
          <Route
            path="/"
            element={authUser ? <HomePage /> : <Navigate to={"/login"} />}
          />
          <Route
            path="/login"
            element={!authUser ? <LoginPage /> : <Navigate to={"/"} />}
          />
          <Route
            path="/signup"
            element={!authUser ? <SignupPage /> : <Navigate to={"/"} />}
          />
          <Route path="/settings" element={<SettingPage />} />
          <Route path="/settings/privacy" element={authUser ? <PrivacyPage /> : <Navigate to={"/login"} />} />
          <Route path="/settings/pro" element={<ProPage />} />
          <Route path="/settings/developer" element={<DeveloperPage />} />
          <Route
            path="/profile"
            element={authUser ? <ProfilePage /> : <Navigate to={"/login"} />}
          />
        </Routes>
      </div>
      <Toaster />
      {authUser && callStatus !== "IDLE" && <VideoCall />}
      {authUser && voiceCallStatus !== "IDLE" && <VoiceCall />}
    </div>
  );
};
export default App;

const AuthImagePattern = ({ title, subtitle }) => {
  return (
    <div className="hidden lg:flex items-center justify-center bg-base-200 p-12">
      <div className="max-w-md text-center">
        <div className="grid grid-cols-3 gap-3 mb-8">
          {[...Array(9)].map((_, i) => (
            <div
              key={i}
              className={`aspect-square rounded-2xl bg-primary/10 ${
                i % 2 === 0 ? "animate-pulse" : ""
              }`}
            />
          ))}
        </div>
        <h2 className="text-2xl font-bold mb-4">{title}</h2>
        <p className="text-base-content/60">{subtitle}</p>
      </div>
    </div>
  );
};

export { AuthImagePattern };

import React from "react";

const getInitials = (name) => {
    if (!name) return "?";
    const names = name.trim().split(" ");
    if (names.length >= 2) {
        return (names[0][0] + names[1][0]).toUpperCase();
    }
    return name.substring(0, 2).toUpperCase();
};

const getColorClass = (name) => {
    if (!name) return "bg-primary/20 text-primary";
    const colors = [
        "bg-primary/20 text-primary",
        "bg-secondary/20 text-secondary",
        "bg-accent/20 text-accent",
        "bg-info/20 text-info",
        "bg-success/20 text-success",
        "bg-warning/20 text-warning",
        "bg-error/20 text-error",
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
};

const Avatar = ({ user, size = "size-10", rounded = "rounded-full", showOnline = false, onlineUsers = [] }) => {
    if (!user) return null;

    const isOnline = showOnline && onlineUsers.includes(user._id);
    const colorClass = getColorClass(user.fullname || user.name);

    return (
        <div className="relative">
            {user.profilePic || user.avatar ? (
                <img
                    src={user.profilePic || user.avatar}
                    alt={user.fullname || user.name || "User"}
                    className={`${size} ${rounded} object-cover bg-base-200 border border-base-300`}
                />
            ) : (
                <div className={`${size} ${rounded} ${colorClass} flex flex-col items-center justify-center border border-base-300`}>
                    <span className="font-semibold text-sm leading-none">{getInitials(user.fullname || user.name)}</span>
                </div>
            )}

            {isOnline && (
                <span className={`absolute bottom-0 right-0 ${size === 'size-10' || size === 'size-[40px]' ? 'w-3 h-3' : 'w-2.5 h-2.5'} bg-green-500 border-[2px] border-base-100 rounded-full z-10`} />
            )}
        </div>
    );
};

export default Avatar;

import { useEffect } from "react";
import { useCallHistoryStore } from "../store/useCallHistoryStore";
import { useAuthStore } from "../store/useAuthStore";
import { Phone, Video, ArrowDownLeft, ArrowUpRight, Clock, XCircle, CheckCircle } from "lucide-react";
import Avatar from "./Avatar";

const CallHistory = () => {
    const { calls, isLoading, getCallHistory, subscribeToCallUpdates, unsubscribeFromCallUpdates } = useCallHistoryStore();
    const { authUser } = useAuthStore();

    useEffect(() => {
        getCallHistory();
        subscribeToCallUpdates();
        return () => unsubscribeFromCallUpdates();
    }, [getCallHistory, subscribeToCallUpdates, unsubscribeFromCallUpdates]);

    if (isLoading) {
        return (
            <div className="flex-1 flex justify-center items-center">
                <span className="loading loading-spinner loading-md text-primary"></span>
            </div>
        );
    }

    if (calls.length === 0) {
        return (
            <div className="flex-1 flex flex-col justify-center items-center text-base-content/30 gap-3">
                <div className="size-16 rounded-full bg-base-200/50 flex items-center justify-center">
                    <Clock size={32} className="opacity-50" />
                </div>
                <p className="text-sm font-medium">No call history</p>
            </div>
        );
    }

    const formatDuration = (seconds) => {
        if (!seconds) return "0s";
        const min = Math.floor(seconds / 60);
        const sec = seconds % 60;
        return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
    };

    const formatTime = (dateString) => {
        const date = new Date(dateString);
        const now = new Date();
        const isToday = date.toDateString() === now.toDateString();

        if (isToday) {
            return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }
        return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    };

    return (
        <div className="flex-1 flex flex-col h-full bg-base-100">
            {/* Header */}
            <div className="flex items-center justify-between p-3 border-b border-base-200">
                <h2 className="text-sm font-bold uppercase tracking-wider opacity-70">Recent Calls</h2>
                {calls.length > 0 && (
                    <button
                        onClick={() => {
                            if (window.confirm("Clear all call history?")) {
                                useCallHistoryStore.getState().clearCallHistory();
                            }
                        }}
                        className="btn btn-ghost btn-xs text-error opacity-70 hover:opacity-100"
                        title="Clear History"
                    >
                        Clear
                    </button>
                )}
            </div>

            {/* List */}
            <div className="flex-1 overflow-y-auto overflow-x-hidden">
                {calls.map((call) => {
                    const isCaller = call.caller._id === authUser._id;
                    const otherUser = isCaller ? call.receiver : call.caller;
                    const isMissed = call.status === "MISSED";
                    const isRejected = call.status === "REJECTED";

                    return (
                        <div key={call._id} className="flex items-center gap-3 p-3 hover:bg-base-200 transition-colors border-b border-base-100 cursor-default group">
                            <Avatar user={otherUser} size="size-10" />

                            {/* Info */}
                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between items-center mb-0.5">
                                    <h3 className={`font-medium text-sm truncate ${isMissed ? 'text-error' : ''}`}>
                                        {otherUser.fullname}
                                    </h3>
                                    <span className="text-[10px] text-base-content/40 whitespace-nowrap ml-2">
                                        {formatTime(call.createdAt)}
                                    </span>
                                </div>

                                <div className="flex items-center gap-1.5 text-xs text-base-content/60">
                                    {/* Direction Icon */}
                                    {isCaller ? (
                                        <ArrowUpRight size={12} className={isMissed || isRejected ? "text-error" : "text-success"} />
                                    ) : (
                                        <ArrowDownLeft size={12} className={isMissed || isRejected ? "text-error" : "text-primary"} />
                                    )}

                                    {/* Status Text */}
                                    <span className={`truncate ${isMissed ? "text-error" : ""}`}>
                                        {call.status === "ENDED" ? (
                                            isCaller ? "Outgoing" : "Incoming"
                                        ) : (
                                            call.status.charAt(0) + call.status.slice(1).toLowerCase()
                                        )}
                                    </span>

                                    {/* Duration */}
                                    {call.duration > 0 && (
                                        <>
                                            <span className="text-base-content/30">ΓÇó</span>
                                            <span>{formatDuration(call.duration)}</span>
                                        </>
                                    )}
                                </div>
                            </div>

                            {/* Call Type Icon */}
                            <div className="opacity-50 group-hover:opacity-100 transition-opacity">
                                {call.callType === "VIDEO" ? (
                                    <Video size={16} className="text-base-content/70" />
                                ) : (
                                    <Phone size={16} className="text-base-content/70" />
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default CallHistory;

import React, { useEffect, useLayoutEffect, useRef, useState } from "react";
import { useChatStore } from "../store/useChattingStore";
import ChatHeader from "./ChatHeader";
import MessageInput from "./MessageInput";
import MessageBubble from "./MessageBubble";
import MessageSkeleton from "./skeletons/MessageSkeleton";
import { useAuthStore } from "../store/useAuthStore";
import { formatMessageTime } from "../lib/util";
import { Trash2, Edit2, Smile } from "lucide-react";
import gsap from "gsap";
import { useProductivityStore } from "../store/useProductivityStore";

import NotesContainer from "./productivity/NotesContainer";
import PollsList from "./productivity/PollsList";
import TimelineScrubber from "./TimelineScrubber";
import MessageStatus from "./MessageStatus";

import GroupSettingsModal from "./GroupSettingsModal";
import UserInfoModal from "./UserInfoModal";
import DeleteMessagesModal from "./DeleteMessagesModal";
import NoChatSelected from "./NoChatSelected";

const ChatContainer = ({ onOpenMemory }) => {
  const {
    messages,
    getMessages,
    getGroupMessages,
    isMessagesLoading,
    subscribeToMessages,
    unsubscribeFromMessages,
    selectedUser,
    deleteMessages,
    editMessage,
    reactToMessage,
    currentTypingUsers,
    showGroupInfo,
    setShowGroupInfo,
    showUserInfo,
    setShowUserInfo,
  } = useChatStore();

  const isGroup = !!selectedUser?.members;
  const { authUser } = useAuthStore();
  const { activeTab, votePoll } = useProductivityStore();

  const messageEndRef = useRef(null);
  const scrollContainerRef = useRef(null);
  const prevChatId = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);
  const [unreadInActiveChat, setUnreadInActiveChat] = useState(0);
  const [editingMessageId, setEditingMessageId] = useState(null);
  const [editText, setEditText] = useState("");
  const [messageToDelete, setMessageToDelete] = useState(null);

  useEffect(() => {
    if (selectedUser) {
      if (isGroup) {
        getGroupMessages(selectedUser._id);
      } else {
        getMessages(selectedUser._id);
      }
      subscribeToMessages();
    }
    return () => unsubscribeFromMessages();
  }, [selectedUser?._id, isGroup, getMessages, getGroupMessages, subscribeToMessages, unsubscribeFromMessages]);

  useLayoutEffect(() => {
    if (messages.length > 0 && selectedUser?._id !== prevChatId.current) {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
      }
      prevChatId.current = selectedUser?._id;
    }
  }, [messages, selectedUser?._id]);

  useEffect(() => {
    if (messages.length > 0 && selectedUser?._id === prevChatId.current) {
      if (scrollContainerRef.current) {
        const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;
        const isNearBottom = scrollHeight - scrollTop - clientHeight < 150;

        const lastMessage = messages[messages.length - 1];
        const isMyNewMessage = lastMessage && (lastMessage.senderId?._id || lastMessage.senderId) === authUser._id && lastMessage.status === "sending";

        if (isNearBottom || isMyNewMessage) {
          if (isMyNewMessage) {
            scrollContainerRef.current.scrollTop = scrollHeight;
          } else {
            scrollContainerRef.current.scrollTo({ top: scrollHeight, behavior: "smooth" });
          }
        } else {
          // If we are scrolled up and a new message arrives from the other user
          const senderIdValue = lastMessage.senderId?._id || lastMessage.senderId;
          if (!isMyNewMessage && senderIdValue !== authUser._id) {
            setUnreadInActiveChat(prev => prev + 1);
            setShowScrollButton(true);
          }
        }
      }
    }
  }, [messages, authUser._id, selectedUser?._id]);

  const handleScroll = () => {
    if (scrollContainerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;
      const nearBottom = scrollHeight - scrollTop - clientHeight < 150;
      setShowScrollButton(!nearBottom || unreadInActiveChat > 0);
      if (nearBottom && unreadInActiveChat > 0) {
        setUnreadInActiveChat(0);
      }
    }
  };

  const scrollToBottom = () => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTo({ top: scrollContainerRef.current.scrollHeight, behavior: "smooth" });
      setUnreadInActiveChat(0);
    }
  };

  const handleEditStart = (message) => {
    setEditingMessageId(message._id);
    setEditText(message.text);
  };

  const handleEditCancel = () => {
    setEditingMessageId(null);
    setEditText("");
  };

  const handleEditSave = async (messageId) => {
    if (editText.trim()) {
      await editMessage(messageId, editText);
      setEditingMessageId(null);
      setEditText("");
    }
  };

  const handleScrollToMessage = (messageId) => {
    const element = document.getElementById(`msg-${messageId}`);
    if (element) {
      element.scrollIntoView({ behavior: "smooth", block: "center" });
      gsap.fromTo(element, { backgroundColor: "rgba(59, 130, 246, 0.1)" }, { backgroundColor: "transparent", duration: 2 });
    }
  };

  const getTypingText = () => {
    if (currentTypingUsers.length === 0) return "";
    if (isGroup) {
      if (currentTypingUsers.length === 1) {
        const sender = selectedUser.members.find(m => m._id === currentTypingUsers[0].senderId);
        return `${sender?.fullname || "Someone"} is typing...`;
      }
      return "Multiple people are typing...";
    }
    return "Typing...";
  };

  if (!selectedUser) return <NoChatSelected />;
  if (isMessagesLoading) {
    return (
      <div className="flex-1 flex flex-col h-full bg-base-200">
        <div className="shrink-0 z-30">
          <ChatHeader onOpenMemory={onOpenMemory} />
        </div>
        <MessageSkeleton />
        <div className="shrink-0 z-30">
          <MessageInput />
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col h-full bg-base-200">

      {/* Fixed Header */}
      <div className="flex-shrink-0 z-30">
        <ChatHeader onOpenMemory={onOpenMemory} />
      </div>

      {showGroupInfo && isGroup && (
        <GroupSettingsModal onClose={() => setShowGroupInfo(false)} />
      )}

      {showUserInfo && !isGroup && (
        <UserInfoModal user={selectedUser} onClose={() => setShowUserInfo(false)} />
      )}

      {/* Delete Message Modal */}
      <DeleteMessagesModal
        isOpen={!!messageToDelete}
        onClose={() => setMessageToDelete(null)}
        onDeleteForMe={() => {
          deleteMessages(messageToDelete._id, "me");
          setMessageToDelete(null);
        }}
        onDeleteForEveryone={() => {
          deleteMessages(messageToDelete._id, "everyone");
          setMessageToDelete(null);
        }}
        canDeleteForEveryone={messageToDelete?.senderId._id === authUser._id || messageToDelete?.senderId === authUser._id}
        count={1}
      />

      {activeTab === "notes" && <NotesContainer />}
      {activeTab === "polls" && <PollsList />}

      {activeTab === "chat" && (
        <>
          {/* Scrollable Messages Area */}
          <div
            className="flex-1 overflow-y-auto w-full relative custom-scrollbar px-4 py-6 space-y-6"
            ref={scrollContainerRef}
            onScroll={handleScroll}
            style={{ WebkitOverflowScrolling: "touch" }}
          >
            <TimelineScrubber messages={messages} onScrollToMessage={handleScrollToMessage} />

            {messages.map((message) => {
              const senderId = message.senderId?._id || message.senderId;
              const isMyMessage = senderId === authUser._id;

              return (
                <MessageBubble
                  key={message._id}
                  message={message}
                  isMyMessage={isMyMessage}
                  authUser={authUser}
                  selectedUser={selectedUser}
                  isGroup={isGroup}
                  isEditing={editingMessageId === message._id}
                  editText={editText}
                  setEditText={setEditText}
                  handleEditSave={handleEditSave}
                  handleEditCancel={handleEditCancel}
                  handleEditStart={handleEditStart}
                  setMessageToDelete={setMessageToDelete}
                  reactToMessage={reactToMessage}
                  votePoll={votePoll}
                />
              );
            })}

            {currentTypingUsers && currentTypingUsers.length > 0 && (
              <div className="flex gap-3">
                <Avatar
                  user={isGroup && currentTypingUsers.length === 1 ? selectedUser.members.find(m => m._id === currentTypingUsers[0].senderId) : selectedUser}
                  size="size-8"
                />
                <div className="bg-base-100 border border-base-300 px-4 py-2.5 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-2">
                  <span className="loading loading-dots loading-xs text-base-content/40"></span>
                  <span className="text-xs text-base-content/40 italic">{getTypingText()}</span>
                </div>
              </div>
            )}

            <div ref={messageEndRef} />
          </div>

          {showScrollButton && (
            <button
              onClick={scrollToBottom}
              className="absolute bottom-20 left-1/2 -translate-x-1/2 overflow-hidden px-4 py-1.5 bg-primary text-primary-content rounded-full shadow-xl animate-bounce z-20 text-sm font-bold flex items-center justify-center border border-primary-content/20 max-w-[90%] whitespace-nowrap"
            >
              {unreadInActiveChat > 0 ? `New Messages (${unreadInActiveChat}) Γåô` : "New Messages Γåô"}
            </button>
          )}

          {/* Fixed Input Area */}
          <div className="chat-input-wrapper shrink-0 z-30 bg-base-200 w-full">
            <MessageInput />
          </div>
        </>
      )
      }
    </div >
  );
};

export default ChatContainer;

import { useState } from "react";
import { X, Video, Lock, ArrowLeft, Phone, FileText, MessageSquare, MoreVertical } from "lucide-react";
import { useAuthStore } from "../store/useAuthStore";
import { useChatStore } from "../store/useChattingStore";
import { useVideoCallStore } from "../store/useVideoCallStore";
import { useVoiceCallStore } from "../store/useVoiceCallStore";
import { useProductivityStore } from "../store/useProductivityStore";
import ProModal from "./ProModal";
import CreateGroupModal from "./CreateGroupModal"; // Assuming this is the 'Group Info' modal basically
import ConfirmModal from "./ConfirmModal";
import Avatar from "./Avatar";
import toast from "react-hot-toast";

const ChatHeader = () => {
  const {
    selectedUser,
    setSelectedUser,
    leaveGroup,
    setShowGroupInfo,
    showGroupInfo,
    showUserInfo,
    setShowUserInfo,
    clearChat,
    deleteChat,
    typingUsers,
  } = useChatStore();
  const { onlineUsers = [], authUser } = useAuthStore();
  const { activeTab, setActiveTab } = useProductivityStore();
  const [showProModal, setShowProModal] = useState(false);
  const [isLeaving, setIsLeaving] = useState(false);

  // Confirm Modal State
  const [confirmModal, setConfirmModal] = useState({
    isOpen: false,
    title: "",
    message: "",
    onConfirm: () => { },
    isDangerous: false,
    confirmText: "Confirm"
  });

  const closeConfirmModal = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const isGroup = !!selectedUser.members;
  const isPro = authUser.plan === "PRO";

  const isTyping = typingUsers?.some(
    (u) => isGroup ? u.groupId === selectedUser._id : u.senderId === selectedUser._id
  );

  const handleVideoCall = () => {
    if (!isPro) {
      setShowProModal(true);
      return;
    }
    useVideoCallStore.getState().startCall(selectedUser._id, selectedUser.fullname);
  };

  const handleVoiceCall = () => {
    if (!isPro) {
      setShowProModal(true);
      return;
    }
    useVoiceCallStore.getState().startCall(selectedUser._id, selectedUser.fullname);
  };

  const confirmAction = (title, message, onConfirm, isDangerous = false, confirmText = "Confirm") => {
    setConfirmModal({
      isOpen: true,
      title,
      message,
      confirmText,
      isDangerous,
      onConfirm: () => {
        onConfirm();
        closeConfirmModal();
      }
    });
  };

  const handleLeaveGroup = async () => {
    if (isLeaving) return;
    confirmAction(
      "Leave Group",
      "Are you sure you want to leave this group?",
      async () => {
        setIsLeaving(true);
        try {
          await leaveGroup(selectedUser._id);
          setSelectedUser(null);
        } finally {
          setIsLeaving(false);
        }
      },
      true,
      "Leave"
    );
  };

  const handleClearChat = () => {
    if (selectedUser) {
      confirmAction(
        "Clear Chat",
        "Clear all messages? This only removes them from your view.",
        async () => {
          await clearChat(selectedUser._id);
          toast.success("Chat cleared");
        },
        true,
        "Clear"
      );
    }
  };

  const handleDeleteChat = () => {
    // Logic to find conversation ID is handled in store usually or we find it here
    // Assuming deleteChat takes user ID or conversation ID. Store says `deleteChat(id)`.
    // Let's pass selectedUser._id, store usually handles finding the convo or we find it.
    // Re-using logic from previous file: find conversation first.
    const conversation = useChatStore.getState().conversations.find(c =>
      c.participants.some(p => p._id === selectedUser._id)
    );

    if (conversation) {
      confirmAction(
        "Delete Chat",
        "Permanently delete this conversation?",
        async () => {
          await deleteChat(conversation._id);
          setSelectedUser(null);
          toast.success("Chat deleted");
        },
        true,
        "Delete"
      );
    } else {
      setSelectedUser(null);
    }
  };

  return (
    <div className="flex flex-col bg-base-100 z-10">
      {showProModal && <ProModal onClose={() => setShowProModal(false)} />}

      <ConfirmModal
        isOpen={confirmModal.isOpen}
        onClose={closeConfirmModal}
        onConfirm={confirmModal.onConfirm}
        title={confirmModal.title}
        message={confirmModal.message}
        confirmText={confirmModal.confirmText}
        isDangerous={confirmModal.isDangerous}
      />

      {/* Main Header - 56px */}
      <div className="h-[56px] px-4 flex items-center justify-between border-b border-base-300">
        <div className="flex items-center gap-3">
          {/* Back Button (Mobile) */}
          <button onClick={() => setSelectedUser(null)} className="lg:hidden p-2 -ml-2 text-base-content/60 hover:bg-base-200 rounded-full">
            <ArrowLeft size={20} />
          </button>

          <div
            className="flex items-center gap-3 cursor-pointer"
            onClick={() => isGroup ? setShowGroupInfo(!showGroupInfo) : setShowUserInfo(!showUserInfo)}
          >
            <Avatar user={selectedUser} size="size-9" showOnline={!isGroup} onlineUsers={onlineUsers} />

            <div className="leading-tight">
              <h3 className="text-base font-semibold text-base-content flex items-center gap-1">
                {isGroup ? selectedUser.name : selectedUser.fullname}
              </h3>
              <div className="text-xs text-base-content/60 h-4 flex items-center overflow-hidden">
                {isTyping ? (
                  <span className="text-primary font-medium flex items-center transition-all duration-300">
                    <span className="animate-pulse">Typing...</span>
                  </span>
                ) : (
                  <span className="transition-all duration-300">
                    {isGroup
                      ? `${selectedUser.members.length} members`
                      : (onlineUsers.includes(selectedUser._id)
                        ? "Online"
                        : "Offline"
                      )
                    }
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-1">
          {!isGroup && (
            <>
              <button
                onClick={handleVoiceCall}
                className={`p-2 rounded-full transition-colors relative group ${!isPro ? "text-base-content/30 hover:text-amber-500" : "text-base-content/40 hover:text-primary hover:bg-base-200"}`}
                title="Voice Call"
              >
                <Phone size={20} />
                {!isPro && <Lock size={10} className="absolute top-1.5 right-1.5 text-amber-500" />}
              </button>

              <button
                onClick={handleVideoCall}
                className={`p-2 rounded-full transition-colors relative group ${!isPro ? "text-base-content/30 hover:text-amber-500" : "text-base-content/40 hover:text-primary hover:bg-base-200"}`}
                title="Video Call"
              >
                <Video size={20} />
                {!isPro && <Lock size={10} className="absolute top-1.5 right-1.5 text-amber-500" />}
              </button>
            </>
          )}

          {/* Menu */}
          <div className="dropdown dropdown-end">
            <button tabIndex={0} className="p-2 text-base-content/40 hover:text-base-content/60 hover:bg-base-200 rounded-full">
              <MoreVertical size={20} />
            </button>
            <ul tabIndex={0} className="dropdown-content menu p-1 shadow-lg bg-base-100 rounded-xl w-48 border border-base-300 mt-1 z-20 text-sm">
              {isGroup ? (
                <>
                  <li><button onClick={() => setShowGroupInfo(true)}>Group Info</button></li>
                  <li><button onClick={handleLeaveGroup} className="text-red-500 hover:bg-red-50">Leave Group</button></li>
                </>
              ) : (
                <>
                  <li><button onClick={() => setShowUserInfo(true)}>Contact Info</button></li>
                  <li><button onClick={handleClearChat}>Clear Chat</button></li>
                  <li><button onClick={handleDeleteChat} className="text-red-500 hover:bg-red-50">Delete Chat</button></li>
                </>
              )}
            </ul>
          </div>

          <button onClick={() => setSelectedUser(null)} className="hidden lg:block p-2 text-base-content/40 hover:text-base-content/60 hover:bg-base-200 rounded-full ml-1">
            <X size={20} />
          </button>
        </div>
      </div>

      {/* Slim Productivity Tabs */}
      <div className="h-[40px] px-4 flex items-center gap-6 border-b border-base-300 bg-base-100">
        <button
          onClick={() => setActiveTab("chat")}
          className={`h-full flex items-center gap-2 text-xs font-medium border-b-2 transition-colors ${activeTab === "chat" ? "border-primary text-primary" : "border-transparent text-base-content/60 hover:text-base-content/70"}`}
        >
          <MessageSquare size={14} /> Chat
        </button>
        <button
          onClick={() => setActiveTab("notes")}
          className={`h-full flex items-center gap-2 text-xs font-medium border-b-2 transition-colors ${activeTab === "notes" ? "border-primary text-primary" : "border-transparent text-base-content/60 hover:text-base-content/70"}`}
        >
          <FileText size={14} /> Notes
        </button>
      </div>
    </div>
  );
};

export default ChatHeader;

import React, { useState, useEffect, useRef } from "react";
import { useChatStore } from "../store/useChattingStore";
import { X, Plus, Trash2, Edit2 } from "lucide-react";
import gsap from "gsap";

const ChatMemory = ({ conversationId, isOpen, onClose }) => {
    const { chatMemory, addMemory, removeMemory } = useChatStore();
    const [newMemory, setNewMemory] = useState("");
    const [isAdding, setIsAdding] = useState(false);
    const panelRef = useRef(null);

    useEffect(() => {
        if (isOpen) {
            gsap.to(panelRef.current, { x: 0, duration: 0.5, ease: "power3.out" });
        } else {
            gsap.to(panelRef.current, { x: "100%", duration: 0.5, ease: "power3.in" });
        }
    }, [isOpen]);

    const handleAdd = async () => {
        if (!newMemory.trim()) return;
        await addMemory(conversationId, newMemory);
        setNewMemory("");
        setIsAdding(false);
    };

    return (
        <div
            ref={panelRef}
            className="fixed top-0 right-0 h-full w-80 bg-base-100 shadow-2xl z-50 transform translate-x-full border-l border-base-300"
        >
            <div className="p-4 border-b border-base-300 flex justify-between items-center bg-base-200/50 backdrop-blur-md">
                <h3 className="font-bold text-lg flex items-center gap-2">
                    ≡ƒºá Chat Memory
                </h3>
                <button onClick={onClose} className="btn btn-ghost btn-sm btn-circle">
                    <X size={20} />
                </button>
            </div>

            <div className="p-4 overflow-y-auto h-[calc(100%-130px)] space-y-4">
                {chatMemory.length === 0 ? (
                    <div className="text-center opacity-50 mt-10">
                        <p>No memories yet.</p>
                        <p className="text-sm">Pin important details here.</p>
                    </div>
                ) : (
                    chatMemory.map((mem) => (
                        <div key={mem._id} className="card bg-base-200 shadow-sm p-3 group relative">
                            <p className="text-sm">{mem.text}</p>
                            <button
                                onClick={() => removeMemory(conversationId, mem._id)}
                                className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 btn btn-xs btn-ghost text-error"
                            >
                                <Trash2 size={14} />
                            </button>
                        </div>
                    ))
                )}
            </div>

            <div className="absolute bottom-0 w-full p-4 border-t border-base-300 bg-base-100">
                {isAdding ? (
                    <div className="flex flex-col gap-2">
                        <textarea
                            className="textarea textarea-bordered w-full h-20"
                            placeholder="Remember..."
                            value={newMemory}
                            onChange={(e) => setNewMemory(e.target.value)}
                        />
                        <div className="flex gap-2 justify-end">
                            <button onClick={() => setIsAdding(false)} className="btn btn-sm btn-ghost">Cancel</button>
                            <button onClick={handleAdd} className="btn btn-sm btn-primary">Save</button>
                        </div>
                    </div>
                ) : (
                    <button onClick={() => setIsAdding(true)} className="btn btn-block btn-outline btn-primary gap-2">
                        <Plus size={18} /> Add Memory
                    </button>
                )}
            </div>
        </div>
    );
};

export default ChatMemory;

import React from "react";
import { AlertTriangle } from "lucide-react";
import Modal from "./Modal";

const ConfirmModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Confirm", cancelText = "Cancel", isDangerous = false }) => {
    if (!isOpen) return null;

    return (
        <Modal onClose={onClose}>
            <div className="bg-base-100 rounded-xl shadow-2xl p-6 w-[90vw] max-w-sm border border-base-200 animate-in zoom-in-95 duration-200 scale-100 relative" onClick={(e) => e.stopPropagation()}>
                <h3 className="text-lg font-bold flex items-center gap-2">
                    {isDangerous && <AlertTriangle className="size-5 text-error" />}
                    {title}
                </h3>
                <p className="py-4 text-base-content/70">{message}</p>
                <div className="flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="btn btn-ghost"
                    >
                        {cancelText}
                    </button>
                    <button
                        onClick={() => {
                            onConfirm();
                            onClose();
                        }}
                        className={`btn ${isDangerous ? "btn-error" : "btn-primary"}`}
                    >
                        {confirmText}
                    </button>
                </div>
            </div>
        </Modal>
    );
};

export default ConfirmModal;

import { useState } from "react";
import { useChatStore } from "../store/useChattingStore";
import { X, Check } from "lucide-react";

const CreateGroupModal = ({ onClose }) => {
    const { friends, createGroup } = useChatStore();
    const [groupName, setGroupName] = useState("");
    const [selectedFriends, setSelectedFriends] = useState([]);
    const [isCreating, setIsCreating] = useState(false);

    const toggleFriend = (friendId) => {
        if (isCreating) return;
        if (selectedFriends.includes(friendId)) {
            setSelectedFriends(selectedFriends.filter((id) => id !== friendId));
        } else {
            setSelectedFriends([...selectedFriends, friendId]);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!groupName.trim() || selectedFriends.length === 0) return;
        if (isCreating) return;

        setIsCreating(true);
        try {
            await createGroup({ name: groupName, members: selectedFriends });
            onClose();
        } finally {
            setIsCreating(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-base-100 rounded-lg p-6 w-full max-w-md shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-semibold">Create New Group</h2>
                    <button onClick={onClose} className="btn btn-sm btn-circle btn-ghost" disabled={isCreating}>
                        <X className="size-5" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="label">
                            <span className="label-text">Group Name</span>
                        </label>
                        <input
                            type="text"
                            placeholder="Enter group name"
                            className="input input-bordered w-full"
                            value={groupName}
                            onChange={(e) => setGroupName(e.target.value)}
                            required
                            disabled={isCreating}
                        />
                    </div>

                    <div>
                        <label className="label">
                            <span className="label-text">Select Members</span>
                        </label>
                        <div className="max-h-60 overflow-y-auto border rounded-lg p-2 space-y-2">
                            {friends.length === 0 ? (
                                <p className="text-center text-zinc-500 py-4">No friends to add</p>
                            ) : (
                                friends.map((friend) => (
                                    <div
                                        key={friend._id}
                                        className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors ${selectedFriends.includes(friend._id) ? "bg-primary/10" : "hover:bg-base-200"
                                            } ${isCreating ? "opacity-50 cursor-not-allowed" : ""}`}
                                        onClick={() => toggleFriend(friend._id)}
                                    >
                                        <div className="relative">
                                            <img
                                                src={friend.profilePic || "/avatar.png"}
                                                alt={friend.fullname}
                                                className="size-10 object-cover rounded-full"
                                            />
                                            {selectedFriends.includes(friend._id) && (
                                                <div className="absolute -top-1 -right-1 bg-primary text-white rounded-full p-0.5">
                                                    <Check className="size-3" />
                                                </div>
                                            )}
                                        </div>
                                        <div className="flex-1">
                                            <div className="font-medium">{friend.fullname}</div>
                                            <div className="text-xs text-zinc-400">@{friend.username}</div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                        <div className="text-xs text-zinc-500 mt-1">
                            {selectedFriends.length} selected
                        </div>
                    </div>

                    <button
                        type="submit"
                        className="btn btn-primary w-full"
                        disabled={!groupName.trim() || selectedFriends.length === 0 || isCreating}
                    >
                        {isCreating ? <span className="loading loading-spinner loading-sm"></span> : "Create Group"}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default CreateGroupModal;

import React from "react";
import Modal from "./Modal";

const DeleteMessagesModal = ({ isOpen, onClose, onDeleteForMe, onDeleteForEveryone, canDeleteForEveryone, count }) => {
    if (!isOpen) return null;

    return (
        <Modal onClose={onClose}>
            <div className="bg-white w-[90vw] max-w-[320px] rounded-2xl p-6 shadow-2xl animate-scaleIn relative overflow-hidden">
                <h3 className="text-lg font-semibold mb-4 text-center text-gray-800">
                    Delete {count} message{count > 1 ? "s" : ""}?
                </h3>

                <div className="flex flex-col gap-3">
                    {canDeleteForEveryone && (
                        <button
                            onClick={() => {
                                onDeleteForEveryone();
                                onClose();
                            }}
                            className="w-full py-2.5 rounded-xl border border-red-100 text-red-500 hover:bg-red-50 transition-colors font-medium text-sm"
                        >
                            Delete for everyone
                        </button>
                    )}

                    <button
                        onClick={() => {
                            onDeleteForMe();
                            onClose();
                        }}
                        className="w-full py-2.5 rounded-xl bg-red-500 text-white hover:bg-red-600 transition-all font-medium text-sm shadow-md hover:shadow-lg"
                    >
                        Delete for me
                    </button>

                    <button
                        onClick={onClose}
                        className="w-full py-2.5 rounded-xl bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors font-medium text-sm mt-1"
                    >
                        Cancel
                    </button>
                </div>
            </div>
        </Modal>
    );
};

export default DeleteMessagesModal;

import { useState, useRef, useEffect } from "react";
import { useChatStore } from "../store/useChattingStore";
import { useAuthStore } from "../store/useAuthStore";
import {
    ArrowLeft,
    UserPlus,
    Edit2,
    Check,
    UserMinus,
    ShieldCheck,
    Camera,
    MoreVertical,
    Users,
    X
} from "lucide-react";
import toast from "react-hot-toast";
import Avatar from "./Avatar";

const GroupSettingsModal = ({ onClose }) => {
    const {
        selectedUser,
        updateGroup,
        addGroupMember,
        removeGroupMember,
        friends,
        promoteToAdmin,
        dismissAsAdmin,
    } = useChatStore();

    const { authUser } = useAuthStore();

    const [name, setName] = useState("");
    const [description, setDescription] = useState("");
    const [imagePreview, setImagePreview] = useState("");

    const [isEditingName, setIsEditingName] = useState(false);
    const [isEditingDescription, setIsEditingDescription] = useState(false);
    const [showAddMember, setShowAddMember] = useState(false);

    const fileInputRef = useRef(null);

    if (!selectedUser) return null;

    const isAdmin =
        selectedUser.admins?.some(
            (admin) => admin._id === authUser?._id
        ) || false;

    // =============================
    // Sync State
    // =============================
    useEffect(() => {
        setName(selectedUser.name || "");
        setDescription(selectedUser.description || "");
        setImagePreview(selectedUser.avatar || "");
    }, [selectedUser]);

    // =============================
    // Handlers
    // =============================

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onloadend = async () => {
            setImagePreview(reader.result);
            await updateGroup(selectedUser._id, {
                avatar: reader.result,
            });
            toast.success("Group icon updated");
        };
        reader.readAsDataURL(file);
    };

    const handleUpdateName = async () => {
        if (!name.trim()) return;
        await updateGroup(selectedUser._id, { name });
        setIsEditingName(false);
        toast.success("Group name updated");
    };

    const handleUpdateDescription = async () => {
        await updateGroup(selectedUser._id, { description });
        setIsEditingDescription(false);
        toast.success("Description updated");
    };

    const handleAddMember = async (friendId) => {
        await addGroupMember(selectedUser._id, friendId);
        toast.success("Member added");
        setShowAddMember(false);
    };

    const handleRemoveMember = async (memberId) => {
        await removeGroupMember(selectedUser._id, memberId);
    };

    const handlePromote = async (memberId) => {
        await promoteToAdmin(selectedUser._id, memberId);
        toast.success("Promoted to admin");
    };

    const handleDismiss = async (memberId) => {
        await dismissAsAdmin(selectedUser._id, memberId);
        toast.success("Dismissed as admin");
    };

    const availableFriends =
        friends?.filter(
            (friend) =>
                !selectedUser.members.some(
                    (member) => member._id === friend._id
                )
        ) || [];

    // =============================
    // UI
    // =============================



    return (
        <div className="absolute top-0 right-0 h-full w-80 bg-base-100 border-l border-base-300 shadow-soft flex flex-col z-40 animate-in slide-in-from-right duration-300">
            {/* Header */}
            <div className="flex items-center gap-4 px-4 py-3 border-b border-base-200 shrink-0 bg-base-100/80 backdrop-blur-md sticky top-0 z-10">
                <button
                    onClick={onClose}
                    className="btn btn-ghost btn-circle btn-sm"
                >
                    <X size={20} />
                </button>

                <div className="flex-1 min-w-0">
                    <h2 className="font-semibold text-lg leading-tight truncate">
                        Group Info
                    </h2>
                    <p className="text-xs opacity-60">
                        {selectedUser.members.length} members
                    </p>
                </div>
            </div>

            {/* Scrollable Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar">

                {/* Avatar Section */}
                <div className="flex flex-col items-center py-8 border-b border-base-200 bg-base-200/30">
                    <div className="relative group">
                        <div className="size-32 rounded-full flex items-center justify-center overflow-hidden shadow-soft border-4 border-base-100">
                            <Avatar user={{ avatar: imagePreview, name: selectedUser.name }} size="size-32" />
                        </div>

                        {isAdmin && (
                            <button
                                onClick={() => fileInputRef.current?.click()}
                                className="absolute bottom-1 right-1 bg-primary text-white p-2.5 rounded-full shadow-lg hover:scale-105 transition-transform"
                                title="Change group icon"
                            >
                                <Camera size={18} />
                            </button>
                        )}

                        <input
                            type="file"
                            ref={fileInputRef}
                            className="hidden"
                            accept="image/*"
                            onChange={handleImageChange}
                        />
                    </div>

                    {/* Name */}
                    <div className="mt-6 text-center w-full px-6">
                        {isEditingName ? (
                            <div className="flex items-center gap-2 justify-center animate-in zoom-in-95 duration-200">
                                <input
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="input input-bordered input-sm text-center font-bold text-xl w-full max-w-xs bg-base-100"
                                    autoFocus
                                    onKeyDown={(e) => {
                                        if (e.key === "Enter") handleUpdateName();
                                        if (e.key === "Escape") setIsEditingName(false);
                                    }}
                                />
                                <button
                                    onClick={handleUpdateName}
                                    className="btn btn-primary btn-sm btn-circle shadow-md flex-shrink-0"
                                >
                                    <Check size={16} />
                                </button>
                                <button
                                    onClick={() => setIsEditingName(false)}
                                    className="btn btn-ghost btn-sm btn-circle text-error flex-shrink-0"
                                >
                                    <X size={16} />
                                </button>
                            </div>
                        ) : (
                            <div className="flex items-center gap-2 justify-center group cursor-pointer" onClick={() => isAdmin && setIsEditingName(true)}>
                                <h1 className="text-2xl font-bold truncate max-w-md">
                                    {selectedUser.name}
                                </h1>
                                {isAdmin && (
                                    <button
                                        className="btn btn-ghost btn-xs btn-circle opacity-0 group-hover:opacity-100 transition-opacity"
                                    >
                                        <Edit2 size={14} />
                                    </button>
                                )}
                            </div>
                        )}
                        <p className="text-sm opacity-50 mt-1">Group ┬╖ {selectedUser.members.length} participants</p>
                    </div>
                </div>

                {/* Description */}
                <div className="p-6 border-b border-base-200">
                    <div className="flex justify-between items-center mb-3">
                        <span className="text-sm font-bold opacity-70 uppercase tracking-wider">
                            Description
                        </span>
                        {isAdmin && !isEditingDescription && (
                            <button
                                onClick={() => setIsEditingDescription(true)}
                                className="btn btn-ghost btn-xs text-primary font-medium"
                            >
                                Edit
                            </button>
                        )}
                    </div>

                    {isEditingDescription ? (
                        <div className="animate-in fade-in duration-200">
                            <textarea
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                className="textarea textarea-bordered w-full text-base leading-relaxed h-24 resize-none bg-base-100"
                                placeholder="Add a group description..."
                                autoFocus
                            />
                            <div className="flex justify-end gap-2 mt-3">
                                <button
                                    onClick={() => setIsEditingDescription(false)}
                                    className="btn btn-ghost btn-sm"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleUpdateDescription}
                                    className="btn btn-primary btn-sm"
                                >
                                    Save
                                </button>
                            </div>
                        </div>
                    ) : (
                        <p className="text-base leading-relaxed opacity-80 whitespace-pre-wrap break-words">
                            {selectedUser.description ||
                                <span className="italic opacity-50">No description provided.</span>}
                        </p>
                    )}
                </div>

                {/* Members */}
                <div className="p-6 pb-20">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-sm font-bold opacity-70 uppercase tracking-wider">
                            {selectedUser.members.length} Participants
                        </span>
                        {isAdmin && (
                            <button
                                onClick={() => setShowAddMember(!showAddMember)}
                                className="btn btn-sm btn-ghost text-primary hover:bg-primary/10 gap-2"
                            >
                                <UserPlus size={18} />
                                Add
                            </button>
                        )}
                    </div>

                    {/* Add Member Dropdown Area */}
                    {showAddMember && (
                        <div className="mb-6 bg-base-200/50 rounded-xl p-4 animate-in slide-in-from-top-2 border border-base-200">
                            <input type="text" placeholder="Search friends..." className="input input-sm input-bordered w-full mb-3 bg-base-100" />
                            <div className="max-h-48 overflow-y-auto space-y-1 custom-scrollbar">
                                {availableFriends.length > 0 ? (
                                    availableFriends.map(friend => (
                                        <button
                                            key={friend._id}
                                            onClick={() => handleAddMember(friend._id)}
                                            className="w-full flex items-center gap-3 p-2 hover:bg-base-100 rounded-lg transition-all text-left"
                                        >
                                            <Avatar user={friend} size="size-8" />
                                            <span className="text-sm font-medium flex-1 truncate">{friend.fullname}</span>
                                            <UserPlus size={16} className="text-primary" />
                                        </button>
                                    ))
                                ) : (
                                    <div className="text-center py-4 text-sm opacity-50">No new friends to add.</div>
                                )}
                            </div>
                        </div>
                    )}

                    <div className="space-y-1">
                        {selectedUser.members.map((member) => {
                            const isMemberAdmin =
                                selectedUser.admins.some(
                                    (a) => a._id === member._id
                                );

                            return (
                                <div
                                    key={member._id}
                                    className="flex items-center justify-between p-2 rounded-xl hover:bg-base-200/50 transition-colors group"
                                >
                                    <div className="flex items-center gap-3 min-w-0">
                                        <div className="relative flex-shrink-0">
                                            <Avatar user={member} size="size-10" />
                                            {isMemberAdmin && (
                                                <div className="absolute -bottom-1 -right-1 bg-primary text-white p-0.5 rounded-full border-2 border-base-100" title="Admin">
                                                    <ShieldCheck size={10} />
                                                </div>
                                            )}
                                        </div>
                                        <div className="min-w-0">
                                            <p className="font-medium text-sm flex items-center gap-2 truncate">
                                                {member.fullname}
