                                    {isAdmin && member._id !== authUser._id && (
                                        <div className="dropdown dropdown-end dropdown-left">
                                            <div
                                                tabIndex={0}
                                                role="button"
                                                className="btn btn-ghost btn-sm btn-circle opacity-0 group-hover:opacity-100 transition-opacity"
