import { useRef, useState, useEffect } from "react";
import { useChatStore } from "../store/useChattingStore";
import { useAuthStore } from "../store/useAuthStore";
import { Image, Send, X, Mic, Smile, Clock, Plus } from "lucide-react";
import toast from "react-hot-toast";
import EmojiPicker from "emoji-picker-react";
import gsap from "gsap";
import ScheduledMessagesModal from "./productivity/ScheduledMessagesModal";

const MessageInput = () => {
  const [text, setText] = useState("");
  const [imagePreview, setImagePreview] = useState(null);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const [showScheduleModal, setShowScheduleModal] = useState(false);
  const [showAttachMenu, setShowAttachMenu] = useState(false); // For Plus button

  const [isRecording, setIsRecording] = useState(false);

  const fileInputRef = useRef(null);
  const textareaRef = useRef(null);
  const emojiPickerRef = useRef(null);
  const attachMenuRef = useRef(null);

  const { sendMessage, sendGroupMessage, selectedUser, sendTypingStart, sendTypingStop, replyToMessage, clearReplyToMessage } = useChatStore();
  const { authUser } = useAuthStore();
  const typingTimeoutRef = useRef(null);
  const isTypingRef = useRef(false);

  const isGroup = !!selectedUser?.members;

  // Close menus when clicking outside and cleanup typing on unmount
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (emojiPickerRef.current && !emojiPickerRef.current.contains(event.target)) {
        setShowEmojiPicker(false);
      }
      if (attachMenuRef.current && !attachMenuRef.current.contains(event.target)) {
        setShowAttachMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      if (isTypingRef.current && selectedUser) {
        const receiverId = selectedUser._id;
        const groupId = selectedUser.members ? selectedUser._id : null;
        sendTypingStop(receiverId, groupId);
      }
    };
  }, [selectedUser, sendTypingStop]);

  // GSAP Animation for Emoji Picker
  useEffect(() => {
    if (showEmojiPicker && emojiPickerRef.current) {
      gsap.fromTo(emojiPickerRef.current,
        { opacity: 0, y: 20, scale: 0.95 },
        { opacity: 1, y: 0, scale: 1, duration: 0.2, ease: "back.out(1.7)" }
      );
    }
  }, [showEmojiPicker]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [text]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      toast.error("Please select an image file");
      return;
    }
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result);
      setShowAttachMenu(false);
    };
    reader.readAsDataURL(file);
  };

  const removeImage = () => {
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const handleSendMessage = async (e) => {
    if (e) e.preventDefault();
    if (!text.trim() && !imagePreview) return;

    setShowEmojiPicker(false);

    // Stop typing
    if (isTypingRef.current) {
      sendTypingStop(selectedUser._id, isGroup ? selectedUser._id : null);
      isTypingRef.current = false;
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }

    // Capture values before clearing state
    const currentText = text;
    const currentImagePreview = imagePreview;

    // Instantly clear input
    setText("");
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.focus(); // Keep keyboard open
    }

    const replyId = replyToMessage?._id;
    if (replyId) clearReplyToMessage();

    try {
      let content = { text: currentText.trim(), image: currentImagePreview, replyTo: replyId };
      // Sending happens in background
      if (isGroup) {
        sendGroupMessage(selectedUser._id, content);
      } else {
        sendMessage(content);
      }
    } catch (error) {
      console.error("Failed to send message async:", error);
    } finally {
      // Ensure focus is regained even if lost
      setTimeout(() => textareaRef.current?.focus(), 10);
    }
  };

  const handleTyping = (e) => {
    const value = e.target.value;
    setText(value);

    // Typing indicator logic
    const receiverId = selectedUser._id;
    const groupId = isGroup ? selectedUser._id : null;

    if (value.trim().length > 0) {
      if (!isTypingRef.current) {
        isTypingRef.current = true;
        sendTypingStart(receiverId, groupId);
      }
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        isTypingRef.current = false;
        sendTypingStop(receiverId, groupId);
      }, 1000);
    } else {
      if (isTypingRef.current) {
        isTypingRef.current = false;
        sendTypingStop(receiverId, groupId);
      }
    }
  };

  const handleEmojiClick = (emojiObject) => {
    setText(prev => prev + emojiObject.emoji);
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const startRecording = () => { toast.success("Voice messages coming soon!"); };

  return (
    <div className="bg-base-100 border-t border-base-300 w-full flex flex-col z-10">

      {/* Reply Preview (Flex Stacked instead of Absolute) */}
      {replyToMessage && (
        <div className="bg-base-200 border-b border-base-300 p-2 px-4 flex items-center justify-between opacity-95">
          <div className="flex flex-col border-l-4 border-primary pl-2 overflow-hidden w-full">
            <span className="text-xs font-bold text-primary truncate">
              Replying to {(replyToMessage.senderId?._id === authUser._id || replyToMessage.senderId === authUser._id) ? "You" : (replyToMessage.senderId?.fullname || selectedUser?.fullname || "User")}
            </span>
