                            <div className="size-24 rounded-full flex items-center justify-center mx-auto mb-4 animate-pulse">
                                <Avatar user={{ name: "Calling" }} size="size-24" />
                            </div>
                            <h3 className="text-2xl font-semibold text-white">Calling...</h3>
