import React, { useEffect, useState, useMemo } from "react";
import { useProductivityStore } from "../../store/useProductivityStore";
import { useChatStore } from "../../store/useChattingStore";
import { CheckCircle2, Circle, Clock, Plus } from "lucide-react";

const GroupTaskList = () => {
    const selectedUser = useChatStore((state) => state.selectedUser);
    const { board, tasks, isBoardLoading, fetchBoard, addTask, moveTask } = useProductivityStore();

    const [newTaskTitle, setNewTaskTitle] = useState("");
    const [isAddingString, setIsAddingString] = useState(false);

    useEffect(() => {
        if (!selectedUser) return;
        fetchBoard(selectedUser._id);
    }, [selectedUser, fetchBoard]);

    const allTasks = useMemo(() => {
        if (!board || !board.columns) return [];
        // Flatten tasks from all columns, but keep track of their status (column)
        const flatTasks = [];
        board.columns.forEach(col => {
            const colTasks = tasks.filter(t => t.columnId === col.id).sort((a, b) => a.order - b.order);
            colTasks.forEach(task => {
                flatTasks.push({ ...task, status: col.title, columnId: col.id });
            });
        });
        return flatTasks;
    }, [board, tasks]);

    const handleAddTask = async (e) => {
        e.preventDefault();
        if (!newTaskTitle.trim() || !board || !board.columns.length) return;

        // Default to first column (usually Todo)
        const firstColumn = board.columns[0];

        await addTask({
            boardId: board._id,
            columnId: firstColumn.id,
            title: newTaskTitle,
            assignedTo: [],
            labels: []
        });

        setNewTaskTitle("");
        setIsAddingString(false);
    };

    // Helper to toggle status (simple implementation: move to next column or toggle todo/done)
    const toggleTaskStatus = async (task) => {
        if (!board) return;
        // Find current column index
        const colIndex = board.columns.findIndex(c => c.id === task.columnId);
        if (colIndex === -1) return;

        // Move to next column, or cycle back to start? 
        // Or if it's "Done", move to "Todo". If "Todo", move to "Done"?
        // Let's assume standard Todo -> In Progress -> Done flow.
        const nextColIndex = (colIndex + 1) % board.columns.length;
        const nextColumn = board.columns[nextColIndex];

        await moveTask(task._id, nextColumn.id, 0);
    };

    if (isBoardLoading && !board) {
        return <div className="p-8 text-center text-base-content/50">Loading tasks...</div>;
    }

    if (!board) return <div className="p-8 text-center text-base-content/50">No tasks found.</div>;

    const getStatusIcon = (status) => {
        const lower = status.toLowerCase();
        if (lower.includes("done") || lower.includes("complete")) return <CheckCircle2 className="text-success" size={20} />;
        if (lower.includes("progress")) return <Clock className="text-warning" size={20} />;
        return <Circle className="text-base-content/30" size={20} />;
    };

    return (
        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-base-100">
            <div className="max-w-3xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold">Group Tasks</h2>
                    <button
                        onClick={() => setIsAddingString(true)}
                        className="btn btn-primary btn-sm gap-2"
                    >
                        <Plus size={16} /> New Task
                    </button>
                </div>

                {isAddingString && (
                    <form onSubmit={handleAddTask} className="mb-6 bg-base-200 p-4 rounded-xl animate-in fade-in slide-in-from-top-2">
                        <input
                            type="text"
                            value={newTaskTitle}
                            onChange={(e) => setNewTaskTitle(e.target.value)}
                            placeholder="What needs to be done?"
                            className="input input-bordered w-full mb-3"
                            autoFocus
                        />
                        <div className="flex justify-end gap-2">
                            <button type="button" onClick={() => setIsAddingString(false)} className="btn btn-ghost btn-sm">Cancel</button>
                            <button type="submit" className="btn btn-primary btn-sm">Add Task</button>
                        </div>
                    </form>
                )}

                <div className="space-y-2">
                    {allTasks.length > 0 ? (
                        allTasks.map((task) => (
                            <div key={task._id} className="group flex items-center gap-4 p-4 bg-base-100 border border-base-200 rounded-xl hover:shadow-md hover:border-base-300 transition-all">
                                <button onClick={() => toggleTaskStatus(task)} className="btn btn-ghost btn-circle btn-sm">
                                    {getStatusIcon(task.status)}
                                </button>
                                <div className="flex-1">
                                    <h3 className={`font-medium ${task.status.toLowerCase().includes('done') ? 'line-through text-base-content/50' : ''}`}>
                                        {task.title}
                                    </h3>
                                    <span className="text-xs text-base-content/50 uppercase tracking-wider font-semibold">
                                        {task.status}
                                    </span>
                                </div>
                                <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                                    {/* Placeholder for more actions */}
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="text-center py-12 bg-base-200/50 rounded-xl border-dashed border-2 border-base-300">
                            <p className="text-base-content/50">No tasks yet. Create one to get started!</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default GroupTaskList;

import React, { useEffect, useState, useMemo, useCallback } from "react";
import { DragDropContext } from "@hello-pangea/dnd";
import { useProductivityStore } from "../../store/useProductivityStore";
import { useChatStore } from "../../store/useChattingStore";
import KanbanColumn from "./KanbanColumn";
import { KanbanSkeleton } from "../skeletons/ProductivitySkeletons";


const KanbanBoard = () => {
    const selectedUser = useChatStore((state) => state.selectedUser);

    // Granular selectors to prevent unnecessary re-renders
    const board = useProductivityStore((state) => state.board);
    const tasks = useProductivityStore((state) => state.tasks);
    const isBoardLoading = useProductivityStore((state) => state.isBoardLoading);
    const fetchBoard = useProductivityStore((state) => state.fetchBoard);
    const moveTask = useProductivityStore((state) => state.moveTask);
    const addTask = useProductivityStore((state) => state.addTask);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newTaskColumn, setNewTaskColumn] = useState("todo");
    const [newTaskTitle, setNewTaskTitle] = useState("");

    const conversations = useChatStore((state) => state.conversations);

    useEffect(() => {
        if (!selectedUser) return;

        let conversationId = selectedUser._id;

        // If it's a 1-on-1 chat (not a group), we need to find the conversation ID
        // Groups usually have their own ID as the conversation ID (or we treat them as such)
        // But for 1-on-1, selectedUser._id is the USER ID, not the CONVERSATION ID.
        const isGroup = selectedUser.groupMembers !== undefined || selectedUser.admins !== undefined;

        if (!isGroup) {
            const conversation = conversations.find(c =>
                c.participants.some(p => p._id === selectedUser._id)
            );
            if (conversation) {
                conversationId = conversation._id;
            } else {
                // No conversation exists yet (e.g. new chat), so no board can exist.
                return;
            }
        }

        fetchBoard(conversationId);
    }, [selectedUser, conversations, fetchBoard]);

    const onDragEnd = useCallback((result) => {
        const { destination, source, draggableId } = result;

        if (!destination) return;

        if (
            destination.droppableId === source.droppableId &&
            destination.index === source.index
        ) {
            return;
        }

        moveTask(draggableId, destination.droppableId, destination.index);
    }, [moveTask]);

    const handleAddTask = useCallback((columnId) => {
        setNewTaskColumn(columnId);
        setIsModalOpen(true);
    }, []);

    const submitTask = async (e) => {
        e.preventDefault();
        if (!newTaskTitle.trim() || !board) return;

        await addTask({
            boardId: board._id,
            columnId: newTaskColumn,
            title: newTaskTitle,
            assignedTo: [],
            labels: []
        });

        setNewTaskTitle("");
        setIsModalOpen(false);
    };

    // Memoize tasks per column to prevent re-rendering all columns when one task changes
    const columnsWithTasks = useMemo(() => {
        if (!board || !board.columns) return [];
        return board.columns.map(column => ({
            ...column,
            tasks: tasks.filter(t => t.columnId === column.id).sort((a, b) => a.order - b.order)
        }));
    }, [board, tasks]);

    if (isBoardLoading && !board) {
        return <KanbanSkeleton />;
    }

    if (!board) return null;

    return (
        <div className="flex-1 overflow-x-auto overflow-y-hidden p-4 md:p-6 bg-gradient-to-br from-base-100 to-base-200/50">
            <div className="flex h-full gap-6 min-w-fit pb-4">
                <DragDropContext onDragEnd={onDragEnd}>
                    {columnsWithTasks.map((column) => (
                        <KanbanColumn
                            key={column.id}
                            column={column}
                            tasks={column.tasks}
                            onAddTask={handleAddTask}
                            onTaskClick={(task) => console.log("Edit task", task)}
                        />
                    ))}
                </DragDropContext>
            </div>

            {/* Add Task Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-base-100 p-6 rounded-xl w-96 shadow-xl">
                        <h3 className="font-bold text-lg mb-4">Add New Task</h3>
                        <form onSubmit={submitTask}>
                            <input
                                type="text"
                                className="input input-bordered w-full mb-4"
                                placeholder="Task title..."
                                value={newTaskTitle}
                                onChange={(e) => setNewTaskTitle(e.target.value)}
                                autoFocus
                            />
                            <div className="flex justify-end gap-2">
                                <button
                                    type="button"
                                    className="btn btn-ghost"
                                    onClick={() => setIsModalOpen(false)}
                                >
                                    Cancel
                                </button>
                                <button type="submit" className="btn btn-primary">
                                    Add Task
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default KanbanBoard;

import React, { memo } from "react";
import { Droppable } from "@hello-pangea/dnd";
import TaskCard from "./TaskCard";
import { Plus } from "lucide-react";

const KanbanColumn = memo(({ column, tasks, onAddTask, onTaskClick }) => {
    return (
        <div className="flex flex-col w-80 min-w-[320px] bg-base-100/40 backdrop-blur-xl border border-base-200/50 rounded-2xl max-h-full shadow-sm">
            {/* Header */}
            <div className="p-4 flex items-center justify-between font-bold text-sm border-b border-base-200/50">
                <div className="flex items-center gap-2">
                    <span className="text-base tracking-tight">{column.title}</span>
                    <span className="bg-base-200 px-2 py-0.5 rounded-full text-xs font-medium opacity-70">{tasks.length}</span>
                </div>
                <button
                    onClick={() => onAddTask(column.id)}
                    className="btn btn-ghost btn-sm btn-circle hover:bg-base-200 transition-colors"
                >
                    <Plus size={16} />
                </button>
            </div>

            {/* Droppable Area */}
            <Droppable droppableId={column.id}>
                {(provided, snapshot) => (
                    <div
                        ref={provided.innerRef}
                        {...provided.droppableProps}
                        className={`
              flex-1 overflow-y-auto p-3 space-y-3 min-h-[100px] transition-colors scrollbar-thin
              ${snapshot.isDraggingOver ? "bg-primary/5" : ""}
            `}
                    >
                        {tasks.map((task, index) => (
                            <TaskCard
                                key={task._id}
                                task={task}
                                index={index}
                                onClick={onTaskClick}
                            />
                        ))}
                        {provided.placeholder}
                    </div>
                )}
            </Droppable>
        </div>
    );
});

