const NotesList = () => {
    const selectedUser = useChatStore((state) => state.selectedUser);

    const notes = useProductivityStore((state) => state.notes);
    const fetchNotes = useProductivityStore((state) => state.fetchNotes);
    const createNote = useProductivityStore((state) => state.createNote);
    const deleteNote = useProductivityStore((state) => state.deleteNote);
    const setActiveNote = useProductivityStore((state) => state.setActiveNote);
    const activeNote = useProductivityStore((state) => state.activeNote);
    const isNotesLoading = useProductivityStore((state) => state.isNotesLoading);

    const conversations = useChatStore((state) => state.conversations);

    const getConversationId = () => {
        if (!selectedUser) return null;

        const isGroup = selectedUser.groupMembers !== undefined || selectedUser.admins !== undefined;
        if (isGroup) return selectedUser._id;

        const conversation = conversations.find(c =>
            c.participants.some(p => p._id === selectedUser._id)
        );
        return conversation ? conversation._id : null;
    };

    useEffect(() => {
        const conversationId = getConversationId();
        if (conversationId) {
            fetchNotes(conversationId);
        }
    }, [selectedUser, conversations, fetchNotes]);

    const handleCreateNote = async () => {
        const conversationId = getConversationId();
        if (!conversationId) return;
        await createNote(conversationId, "Untitled Note", "");
    };

    const handleDeleteNote = (noteId) => {
        if (window.confirm("Delete this note?")) deleteNote(noteId);
    };

    if (isNotesLoading && notes.length === 0) {
        return (
            <div className="w-64 border-r border-base-300 bg-base-200/30 flex flex-col h-full">
                <div className="p-4 space-y-4 animate-pulse">
                    {[1, 2, 3, 4, 5].map(i => <div key={i} className="h-12 bg-base-300 rounded"></div>)}
                </div>
            </div>
        );
    }

    return (
        <div className="w-full flex flex-col h-full">
            <div className="p-4 border-b border-base-200/50 flex items-center justify-between">
                <h3 className="font-bold text-sm tracking-tight">Notes</h3>
                <button onClick={handleCreateNote} className="btn btn-xs btn-circle btn-primary shadow-sm hover:shadow-md transition-shadow">
                    <Plus size={14} />
                </button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {notes.map((note) => (
                    <NoteItem
                        key={note._id}
                        note={note}
                        isActive={activeNote?._id === note._id}
                        onClick={setActiveNote}
                        onDelete={handleDeleteNote}
                    />
                ))}

                {notes.length === 0 && (
                    <div className="text-center py-8 opacity-50 text-sm">
                        No notes yet. <br /> Click + to create one.
                    </div>
                )}
            </div>
        </div>
    );
};

export default NotesList;

import React, { useEffect, useState, memo } from "react";
import { useProductivityStore } from "../../store/useProductivityStore";
import { useChatStore } from "../../store/useChattingStore";
import { useAuthStore } from "../../store/useAuthStore";
import { Plus, BarChart2, CheckCircle } from "lucide-react";
import { PollsSkeleton } from "../skeletons/ProductivitySkeletons";

const PollItem = memo(({ poll, currentUserId, onVote }) => {
    const totalVotes = poll.options.reduce((acc, opt) => acc + opt.voteCount, 0);

    return (
        <div className="card bg-base-200 shadow-sm border border-base-300">
            <div className="card-body p-5">
                <h3 className="font-bold text-lg mb-4">{poll.question}</h3>

                <div className="space-y-3">
                    {poll.options.map((option, idx) => {
                        const percentage = totalVotes === 0 ? 0 : Math.round((option.voteCount / totalVotes) * 100);
                        const isVoted = poll.votes.some(v => v.userId === currentUserId && v.optionIndex === idx);

                        return (
                            <div
                                key={idx}
                                onClick={() => onVote(poll._id, idx)}
                                className={`
            relative p-3 rounded-lg cursor-pointer border transition-all overflow-hidden
            ${isVoted ? "border-primary bg-primary/5" : "border-base-300 hover:bg-base-300/50"}
          `}
                            >
                                {/* Progress Bar Background */}
                                <div
                                    className="absolute inset-0 bg-primary/10 transition-all duration-500"
                                    style={{ width: `${percentage}%` }}
                                />

                                <div className="relative flex items-center justify-between z-10">
                                    <span className="font-medium flex items-center gap-2">
                                        {option.text}
                                        {isVoted && <CheckCircle size={14} className="text-primary" />}
                                    </span>
                                    <span className="text-sm opacity-70 font-mono">
                                        {percentage}% ({option.voteCount})
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>

                <div className="mt-4 text-xs opacity-50 text-right">
                    Total votes: {totalVotes}
                </div>
            </div>
        </div>
    );
});

const PollsList = () => {
    const selectedUser = useChatStore((state) => state.selectedUser);
    const authUser = useAuthStore((state) => state.authUser);

    const polls = useProductivityStore((state) => state.polls);
    const fetchPolls = useProductivityStore((state) => state.fetchPolls);
    const createPoll = useProductivityStore((state) => state.createPoll);
    const votePoll = useProductivityStore((state) => state.votePoll);
    const isPollsLoading = useProductivityStore((state) => state.isPollsLoading);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [question, setQuestion] = useState("");
    const [options, setOptions] = useState(["", ""]);

    useEffect(() => {
        if (selectedUser?._id) {
            fetchPolls(selectedUser._id);
        }
    }, [selectedUser?._id, fetchPolls]);

    const handleCreatePoll = async (e) => {
        e.preventDefault();
        const validOptions = options.filter(o => o.trim());
        if (!question.trim() || validOptions.length < 2) return;

        await createPoll({
            conversationId: selectedUser._id,
            question,
            options: validOptions
        });

        setIsModalOpen(false);
        setQuestion("");
        setOptions(["", ""]);
    };

    const addOption = () => setOptions([...options, ""]);
    const updateOption = (index, value) => {
        const newOptions = [...options];
        newOptions[index] = value;
        setOptions(newOptions);
    };

    if (isPollsLoading && polls.length === 0) {
        return <PollsSkeleton />;
    }

    return (
        <div className="flex-1 bg-base-100 p-4 overflow-y-auto">
            <div className="max-w-2xl mx-auto">
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        <BarChart2 /> Polls
                    </h2>
                    <button
                        onClick={() => setIsModalOpen(true)}
                        className="btn btn-primary btn-sm gap-2"
                    >
                        <Plus size={16} /> Create Poll
                    </button>
                </div>

                <div className="space-y-6">
                    {polls.map((poll) => (
                        <PollItem
                            key={poll._id}
                            poll={poll}
                            currentUserId={authUser._id}
                            onVote={votePoll}
                        />
                    ))}

                    {polls.length === 0 && (
                        <div className="text-center py-12 opacity-50">
                            <BarChart2 size={48} className="mx-auto mb-4 opacity-20" />
                            <p>No polls yet. Create one to ask the group!</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Create Poll Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-base-100 p-6 rounded-xl w-96 shadow-xl">
                        <h3 className="font-bold text-lg mb-4">Create New Poll</h3>
                        <form onSubmit={handleCreatePoll}>
                            <div className="form-control mb-4">
                                <label className="label">
                                    <span className="label-text">Question</span>
                                </label>
                                <input
                                    type="text"
                                    className="input input-bordered w-full"
                                    placeholder="Ask something..."
                                    value={question}
                                    onChange={(e) => setQuestion(e.target.value)}
                                    autoFocus
                                />
                            </div>

                            <div className="form-control mb-4">
                                <label className="label">
                                    <span className="label-text">Options</span>
                                </label>
                                {options.map((opt, idx) => (
                                    <input
                                        key={idx}
                                        type="text"
                                        className="input input-bordered w-full mb-2 input-sm"
                                        placeholder={`Option ${idx + 1}`}
                                        value={opt}
                                        onChange={(e) => updateOption(idx, e.target.value)}
                                    />
                                ))}
                                <button
                                    type="button"
                                    onClick={addOption}
                                    className="btn btn-ghost btn-xs w-full mt-1"
                                >
                                    + Add Option
                                </button>
                            </div>

                            <div className="flex justify-end gap-2 mt-6">
                                <button
                                    type="button"
                                    className="btn btn-ghost"
                                    onClick={() => setIsModalOpen(false)}
                                >
                                    Cancel
                                </button>
                                <button type="submit" className="btn btn-primary">
                                    Create Poll
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default PollsList;

import React, { useState, useEffect } from "react";
import { useProductivityStore } from "../../store/useProductivityStore";
import { useChatStore } from "../../store/useChattingStore";
import { Calendar, Clock, X, Trash2 } from "lucide-react";

const ScheduledMessagesModal = ({ onClose }) => {
    const { selectedUser, conversations } = useChatStore();
    const {
        scheduledMessages,
        fetchScheduledMessages,
        scheduleMessage,
        cancelScheduledMessage,
        isScheduledLoading
    } = useProductivityStore();

    const [content, setContent] = useState("");
    const [date, setDate] = useState("");
    const [time, setTime] = useState("");

    const getConversationId = () => {
        if (!selectedUser) return null;

        const isGroup = selectedUser.groupMembers !== undefined || selectedUser.admins !== undefined; // Check if it's a group
        if (isGroup) return selectedUser._id;

        const conversation = conversations.find(c =>
            c.participants.some(p => p._id === selectedUser._id)
        );
        return conversation ? conversation._id : null;
    };

    useEffect(() => {
        const conversationId = getConversationId();
        if (conversationId) {
            fetchScheduledMessages(conversationId);
        }
    }, [selectedUser?._id, conversations, fetchScheduledMessages]);

    const handleSchedule = async (e) => {
        e.preventDefault();
        if (!content.trim() || !date || !time) return;

        const conversationId = getConversationId();
        if (!conversationId) {
            alert("No conversation found. Please send a message first to start a conversation.");
            return;
        }

        const scheduledAt = new Date(`${date}T${time}`);
        if (scheduledAt <= new Date()) {
            alert("Please select a future time");
            return;
        }

        await scheduleMessage({
            conversationId,
            content,
            scheduledAt
        });

        setContent("");
        setDate("");
        setTime("");
    };

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-base-100/80 backdrop-blur-xl border border-base-200 p-6 rounded-2xl w-full max-w-md shadow-2xl max-h-[80vh] flex flex-col animate-in fade-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between mb-6">
                    <h3 className="font-bold text-lg flex items-center gap-2 text-base-content/90">
                        <Clock size={20} className="text-primary" />
                        <span>Scheduled Messages</span>
                    </h3>
                    <button onClick={onClose} className="btn btn-ghost btn-sm btn-circle hover:bg-base-200/50">
                        <X size={20} />
                    </button>
                </div>

                {/* Create Form */}
                <form onSubmit={handleSchedule} className="mb-6 p-1 bg-base-200/30 rounded-xl border border-base-200/50">
                    <textarea
                        className="textarea textarea-ghost w-full mb-2 bg-transparent focus:bg-base-100/50 transition-colors text-base resize-none focus:outline-none"
                        placeholder="Type your message to schedule..."
                        value={content}
                        onChange={(e) => setContent(e.target.value)}
                        rows={3}
                    />
                    <div className="flex gap-2 p-2">
                        <div className="flex-1 flex gap-2 bg-base-100/50 rounded-lg p-1 border border-base-200/50">
                            <input
                                type="date"
                                className="input input-ghost input-xs w-full focus:outline-none focus:bg-transparent text-xs"
                                value={date}
                                onChange={(e) => setDate(e.target.value)}
                            />
                            <div className="w-px bg-base-300 my-1"></div>
                            <input
                                type="time"
                                className="input input-ghost input-xs w-full focus:outline-none focus:bg-transparent text-xs"
                                value={time}
                                onChange={(e) => setTime(e.target.value)}
                            />
                        </div>
                        <button type="submit" className="btn btn-primary btn-sm shadow-lg shadow-primary/20">
                            Schedule
                        </button>
                    </div>
                </form>

                {/* List */}
                <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                    {isScheduledLoading ? (
                        <div className="text-center opacity-50 py-8">Loading...</div>
                    ) : scheduledMessages.length === 0 ? (
                        <div className="text-center opacity-40 py-8 flex flex-col items-center gap-2">
                            <Clock size={32} className="opacity-20" />
                            <p className="text-sm">No scheduled messages</p>
                        </div>
                    ) : (
                        scheduledMessages.map((msg) => (
                            <div key={msg._id} className="p-3 bg-base-100/50 border border-base-200/50 rounded-xl flex items-center justify-between group hover:border-primary/30 transition-colors shadow-sm">
                                <div className="flex-1 min-w-0 mr-3">
                                    <p className="font-medium truncate text-sm text-base-content/90">{msg.content}</p>
                                    <p className="text-[10px] opacity-60 flex items-center gap-1 mt-1 font-mono">
                                        <Calendar size={10} />
                                        {new Date(msg.scheduledAt).toLocaleString(undefined, { dateStyle: 'medium', timeStyle: 'short' })}
                                    </p>
                                </div>
                                <button
                                    onClick={() => cancelScheduledMessage(msg._id)}
                                    className="btn btn-ghost btn-xs btn-circle text-error/70 hover:text-error hover:bg-error/10 transition-all"
                                >
                                    <Trash2 size={14} />
                                </button>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
};

export default ScheduledMessagesModal;

import React, { memo } from "react";
import { Draggable } from "@hello-pangea/dnd";
import { Calendar, User, Tag } from "lucide-react";

const TaskCard = memo(({ task, index, onClick }) => {
    return (
        <Draggable draggableId={task._id} index={index}>
            {(provided, snapshot) => (
                <div
                    ref={provided.innerRef}
                    {...provided.draggableProps}
                    {...provided.dragHandleProps}
                    onClick={() => onClick(task)}
                    className={`
            bg-base-100 p-4 rounded-xl shadow-sm mb-3 border border-base-200/60 
            hover:shadow-md hover:-translate-y-1 transition-all duration-200 cursor-grab active:cursor-grabbing select-none
            ${snapshot.isDragging ? "shadow-xl rotate-2 scale-105 z-50 ring-2 ring-primary/20" : ""}
          `}
                    style={{ ...provided.draggableProps.style }}
                >
                    {/* Labels */}
                    {task.labels && task.labels.length > 0 && (
                        <div className="flex flex-wrap gap-1.5 mb-3">
                            {task.labels.map((label, i) => (
                                <span
                                    key={i}
                                    className="text-[10px] px-2 py-1 rounded-md font-semibold tracking-wide uppercase"
                                    style={{ backgroundColor: label.color + "15", color: label.color, border: `1px solid ${label.color}30` }}
                                >
                                    {label.text}
                                </span>
                            ))}
                        </div>
                    )}

                    <h4 className="font-medium text-sm mb-1 break-all whitespace-normal">{task.title}</h4>

                    <div className="flex items-center justify-between mt-3 text-xs opacity-60">
                        {task.dueDate && (
                            <div className="flex items-center gap-1">
                                <Calendar size={12} />
                                <span>{new Date(task.dueDate).toLocaleDateString()}</span>
                            </div>
                        )}

                        {task.assignedTo && task.assignedTo.length > 0 && (
                            <div className="flex -space-x-1">
                                {task.assignedTo.slice(0, 3).map((userId, i) => (
                                    <div key={i} className="size-5 rounded-full bg-primary/20 border border-base-100 flex items-center justify-center text-[8px]">
                                        <User size={10} />
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            )}
        </Draggable>
    );
});

export default TaskCard;

