import { useEffect, useState, useRef } from "react";
import { X, ChevronLeft, ChevronRight, Eye } from "lucide-react";
import { useStatusStore } from "../../store/useStatusStore";
import { useAuthStore } from "../../store/useAuthStore";
import StatusViewersSheet from "./StatusViewersSheet";

const StatusViewer = ({
    initialStoryIndex = 0,
    stories,
    onClose,
    userId, // Owner of the stories
    onNextUser,
    onPrevUser
}) => {
    const [currentStoryIndex, setCurrentStoryIndex] = useState(initialStoryIndex);
    const [progress, setProgress] = useState(0);
    const [showViewers, setShowViewers] = useState(false);
    const { viewStatus } = useStatusStore();
    const { authUser } = useAuthStore();

    const currentStory = stories[currentStoryIndex];
    const isVideo = currentStory?.type === "video";
    const duration = isVideo ? (currentStory.duration || 15) : 5; // Default 5s for image/text

    const videoRef = useRef(null);
    const viewTimerRef = useRef(null);

    // Handle View Counting (2-second Timer)
    useEffect(() => {
        // Reset timer on change
        if (viewTimerRef.current) clearTimeout(viewTimerRef.current);

        if (currentStory && currentStory._id && userId !== authUser?._id) {
            // Only count if NOT owner
            viewTimerRef.current = setTimeout(() => {
                viewStatus(userId, currentStory._id);
            }, 2000); // 2 seconds threshold
        }

        return () => {
            if (viewTimerRef.current) clearTimeout(viewTimerRef.current);
        };
    }, [currentStoryIndex, userId, currentStory?._id]);

    // Auto Advance Logic
    useEffect(() => {
        if (showViewers) return; // Pause auto-advance when viewing list

        setProgress(0);
        const startTime = Date.now();

        const interval = setInterval(() => {
            const elapsed = Date.now() - startTime;
            const calculatedProgress = Math.min((elapsed / (duration * 1000)) * 100, 100);
            setProgress(calculatedProgress);

            if (calculatedProgress >= 100) {
                handleNext();
            }
        }, 50);

        return () => clearInterval(interval);
    }, [currentStoryIndex, duration, showViewers]);

    const handleNext = () => {
        if (currentStoryIndex < stories.length - 1) {
            setCurrentStoryIndex(prev => prev + 1);
        } else {
            // End of stories for this user
            if (onNextUser) onNextUser();
            else onClose();
        }
    };

    const handlePrev = () => {
        if (currentStoryIndex > 0) {
            setCurrentStoryIndex(prev => prev - 1);
        } else {
            if (onPrevUser) onPrevUser();
        }
    };

    if (!currentStory) return null;

    return (
        <div className="w-full h-full flex items-center justify-center bg-black relative">
            <div className="relative w-full h-full bg-zinc-900 overflow-hidden flex flex-col">

                {/* Progress Bars */}
                <div className="absolute top-0 left-0 right-0 z-20 flex gap-1 p-2">
                    {stories.map((story, idx) => (
                        <div key={story._id} className="h-1 flex-1 bg-white/30 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-white transition-all duration-75 ease-linear"
                                style={{
                                    width: idx < currentStoryIndex ? "100%" : idx === currentStoryIndex ? `${progress}%` : "0%"
                                }}
                            />
                        </div>
                    ))}
                </div>

                {/* Header */}
                <div className="absolute top-4 left-0 right-0 z-20 px-4 py-2 flex items-center justify-between pointer-events-none">
                    <div className="flex items-center gap-2 pointer-events-auto">
                        <button onClick={onClose} className="p-1 rounded-full bg-black/20 text-white hover:bg-black/40 backdrop-blur-sm">
                            <ChevronLeft size={20} />
                        </button>
                    </div>
                    <button onClick={onClose} className="p-1 rounded-full bg-black/20 text-white hover:bg-black/40 backdrop-blur-sm pointer-events-auto">
                        <X size={20} />
                    </button>
                </div>

                {/* Navigation Overlays */}
                <div className="absolute inset-y-0 left-0 w-1/3 z-10 cursor-w-resize" onClick={handlePrev} />
                <div className="absolute inset-y-0 right-0 w-1/3 z-10 cursor-e-resize" onClick={handleNext} />

                {/* Media */}
                <div className="flex-1 flex items-center justify-center bg-black">
                    {currentStory.type === "text" ? (
                        <div
                            className="w-full h-full flex items-center justify-center p-8 text-center text-white font-bold text-2xl break-words"
                            style={{ backgroundColor: currentStory.color || "#000" }}
                        >
                            {currentStory.content}
                        </div>
                    ) : currentStory.type === "video" ? (
                        <video
                            src={currentStory.content}
                            className="w-full h-full object-contain"
                            autoPlay={!showViewers}
                            muted={false} // Maybe allow sound? User didn't specify. Default muted maybe better for autoplay policies but apps usually allow sound.
                            ref={videoRef}
                        />
                    ) : (
                        <img src={currentStory.content} className="w-full h-full object-contain" alt="Status" />
                    )}
                </div>

                {/* Footer / Caption / Views */}
                <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/80 to-transparent z-20 pointer-events-none">
                    {userId === authUser?._id && (
                        <div className="flex flex-col items-center text-white/80 pointer-events-auto">
                            <button
                                className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/10 backdrop-blur-md hover:bg-white/20 transition-all cursor-pointer"
                                onClick={(e) => { e.stopPropagation(); setShowViewers(true); }}
                            >
                                <Eye size={16} />
                                <span className="text-sm font-medium">{currentStory.viewerCount}</span>
                            </button>
                        </div>
                    )}
                </div>

                {/* Viewer Sheet */}
                <StatusViewersSheet
                    storyId={currentStory._id}
                    isOpen={showViewers}
                    onClose={() => setShowViewers(false)}
                />

            </div>
        </div>
    );
};

export default StatusViewer;

import { useEffect, useState } from "react";
import { X, Clock, User } from "lucide-react";
import { useStatusStore } from "../../store/useStatusStore";
import { useAuthStore } from "../../store/useAuthStore";
import { formatDistanceToNow } from "date-fns";
import Avatar from "../Avatar";

const StatusViewersSheet = ({ storyId, isOpen, onClose }) => {
    const { fetchStatusViewers } = useStatusStore();
    const { socket } = useAuthStore.getState();
    const [viewers, setViewers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [animate, setAnimate] = useState(false);

    useEffect(() => {
        if (isOpen) {
            // Trigger animation on open
            requestAnimationFrame(() => setAnimate(true));
            loadViewers();
        } else {
            setAnimate(false);
        }
    }, [isOpen, storyId]);

    const loadViewers = async () => {
        setLoading(true);
        const data = await fetchStatusViewers(storyId);
        setViewers(data || []);
        setLoading(false);
    };

    // Real-time listener for new views
    useEffect(() => {
        if (!isOpen || !socket) return;

        const handleNewView = (data) => {
            // data: { storyId, viewer: { _id, username, profilePic, viewedAt } }
            if (data.storyId === storyId) {
                setViewers((prev) => {
                    // Check duplicate
                    if (prev.find(v => v._id === data.viewer._id)) return prev;
                    // Prepend new viewer
                    return [data.viewer, ...prev];
                });
            }
        };

        socket.on("status:viewed", handleNewView);

        return () => {
            socket.off("status:viewed", handleNewView);
        };
    }, [isOpen, storyId, socket]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center">
            {/* Backdrop */}
            <div
                className={`absolute inset-0 bg-black/50 backdrop-blur-sm transition-opacity duration-300 ${animate ? "opacity-100" : "opacity-0"}`}
                onClick={onClose}
            />

            {/* Sheet / Modal */}
            <div
                className={`
                    relative w-full max-w-md bg-base-100 rounded-t-2xl sm:rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[80vh]
                    transition-all duration-300 ease-in-out transform
                    ${animate ? "translate-y-0 sm:scale-100 opacity-100" : "translate-y-full sm:translate-y-0 sm:scale-95 opacity-0"}
                `}
            >
                {/* Header */}
                <div className="p-4 border-b border-base-200 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <h3 className="font-bold text-lg">Viewed by {viewers.length}</h3>
                    </div>
                    <button onClick={onClose} className="btn btn-sm btn-circle btn-ghost">
                        <X size={20} />
                    </button>
                </div>

                {/* List */}
                <div className="overflow-y-auto flex-1 p-0">
                    {loading ? (
                        <div className="p-8 text-center text-zinc-500">
                            <span className="loading loading-spinner loading-md"></span>
                        </div>
                    ) : viewers.length === 0 ? (
                        <div className="p-8 text-center text-zinc-500 flex flex-col items-center gap-2">
                            <Clock className="size-8 opacity-20" />
                            <p>No views yet</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-base-200">
                            {viewers.map((viewer) => (
                                <div key={viewer._id} className="flex items-center gap-3 p-4 hover:bg-base-200/50 transition-colors">
                                    <Avatar user={{ ...viewer, profilePic: viewer.profilePic, name: viewer.username }} size="size-10" />
                                    <div className="flex-1 min-w-0">
                                        <div className="font-medium truncate">{viewer.username}</div>
                                        <div className="text-xs text-zinc-500 flex items-center gap-1">
                                            {formatDistanceToNow(new Date(viewer.viewedAt), { addSuffix: true })}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

